"use client";

import React from "react";
import { useRouter } from "next/navigation";
import AddExpenseModal from "./components/AddExpenseModal";
import { useTripsAndExpenses } from "./useTripsAndExpenses";
import { apiUrl } from "../../lib/api";
import {
  StyledContainer,
  StyledHeader,
  StyledButtonContainer,
  StyledBackButton,
  StyledMessage,
  StyledPaginationContainer,
  StyledPaginationButton,
  StyledPaginationInfo,
  StyledTableHeader,
  StyledTableRow,
  StyledTableCell,
  StyledExpenseTable,
  StyledSyncButton,
} from "./ExpenseList.styles";

const ExpenseList: React.FC = () => {
  const router = useRouter();
  const {
    expenses,
    trips,
    loading,
    selectedTrip,
    setSelectedTrip,
    pagination,
    loadExpenses,
    handleAddExpense,
  } = useTripsAndExpenses();

  const { currentPage, hasNextPage, hasPrevPage } = pagination;
  const dollarExchange = selectedTrip?.dolarExchange ?? 1;
  const round2 = (value: number) => Math.round(value * 100) / 100;

  const getExchange = (exchange: string) => {
    const symbols: Record<string, string> = {
      Pesos: "$",
      Dólar: "U$D",
      Real: "R$",
    };

    return symbols[exchange] ?? "-";
  };

  const getPesosAmount = (expense: number, exchange: string) => {
    return round2(exchange === "Dólar" ? expense * dollarExchange : expense);
  };

  const getDollarAmount = (expense: number, exchange: string) => {
    return round2(exchange === "Pesos" ? expense / dollarExchange : expense);
  };

  const renderExpenseContent = () => {
    if (loading) {
      return <StyledMessage>Loading expenses...</StyledMessage>;
    }
    if (expenses.length === 0) {
      return <StyledMessage>No expenses found.</StyledMessage>;
    }
    return (
      <StyledExpenseTable>
        <thead>
          <tr>
            <StyledTableHeader>Date</StyledTableHeader>
            <StyledTableHeader>Description</StyledTableHeader>
            <StyledTableHeader>Amount</StyledTableHeader>
            <StyledTableHeader>Pesos</StyledTableHeader>
            <StyledTableHeader>Dollar</StyledTableHeader>
          </tr>
        </thead>
        <tbody>
          {expenses.map((expense) => (
            <StyledTableRow key={expense.id}>
              <StyledTableCell>{expense.date ? new Date(expense.date).toLocaleDateString() : "-"}</StyledTableCell>
              <StyledTableCell>{expense.type}</StyledTableCell>
              <StyledTableCell>{getExchange(expense.exchange)} {expense.amount}</StyledTableCell>
              <StyledTableCell>{"$ " + getPesosAmount(expense.amount, expense.exchange)}</StyledTableCell>
              <StyledTableCell>{"U$D " + getDollarAmount(expense.amount, expense.exchange)}</StyledTableCell>
            </StyledTableRow>
          ))}
        </tbody>
      </StyledExpenseTable>
    );
  };

  const handleSyncClick = async () => {
    try {
        const response = await fetch(apiUrl("/api/admin/sync-sheets"), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });
        
        const data = await response.json();
        
        if (data.success) {
            alert(data.message);
        } else {
            alert("Error: " + data.message);
        }
    } catch {
        alert("Cannot connect with server. Please try again later.");
    }
};

  return (
    <StyledContainer>
      <StyledHeader>Expense List</StyledHeader>
      <StyledButtonContainer>
        <StyledBackButton onClick={() => router.push("/")}>
          ← Back to Home
        </StyledBackButton>
        <AddExpenseModal onAddExpense={handleAddExpense} />
        <StyledSyncButton onClick={() => handleSyncClick()}>
          Sync with Google Sheets
        </StyledSyncButton>
      </StyledButtonContainer>

      <div style={{ marginBottom: "20px", display: "flex", gap: "10px", flexWrap: "wrap" }}>
        <button
          key="all"
          onClick={() => setSelectedTrip(null)}
          style={{
            padding: "8px 16px",
            backgroundColor: selectedTrip === null ? "#4ecdc4" : "#f0f0f0",
            color: selectedTrip === null ? "white" : "#333",
            border: "none",
            borderRadius: "20px",
            cursor: "pointer",
            fontWeight: "bold",
          }}
        >
          All
        </button>
        {trips.map((trip) => (
          <button
            key={trip.id}
            onClick={() => setSelectedTrip(trip)}
            style={{
              padding: "8px 16px",
              backgroundColor: selectedTrip?.id === trip.id ? "#4ecdc4" : "#f0f0f0",
              color: selectedTrip?.id === trip.id ? "white" : "#333",
              border: "none",
              borderRadius: "20px",
              cursor: "pointer",
              fontWeight: "bold",
            }}
          >
            {trip.destiny}
          </button>
        ))}
      </div>
      <StyledHeader>Total Expenses: {expenses.length} - Dólar: {selectedTrip?.dolarExchange ?? "-"}</StyledHeader>
      <StyledExpenseTable>{renderExpenseContent()}</StyledExpenseTable>
      
      <StyledPaginationContainer>
        <StyledPaginationButton
          disabled={!hasPrevPage}
          onClick={() => loadExpenses(currentPage - 1)}
        >
          ← Previous
        </StyledPaginationButton>

        <StyledPaginationInfo>
           Showing {expenses.length} expenses
        </StyledPaginationInfo>

        <StyledPaginationButton
          disabled={!hasNextPage}
          onClick={() => loadExpenses(currentPage + 1)}
        >
          Next →
        </StyledPaginationButton>
      </StyledPaginationContainer>
    </StyledContainer>
  );
};

export default ExpenseList;